INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'acharya'), 'header', 'From Campus Conversations to Corporate Confidence', 'Great careers begin with clear communication. At Acharya Institute, Bangalore, the gap between technical skills and professional readiness was evident among students preparing for the job market. Recognizing this, Rareminds was brought in to bridge the communication gap and empower students with the skills they need to thrive in the real world.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'introduction', 'Introduction', 'In May 2022–2023, Rareminds conducted a high-impact 5-day Business Communication course for over 700 students across the Physiotherapy, MBA, and MCA departments. The sessions were tailored to enhance industry-specific communication, presentation skills, and professional behavior. This was followed by pre-placement readiness training for 120 MBA and 233 MCA students in 2024, building confidence right before they stepped into the hiring ecosystem.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'modules', 'Modules Covered', 'Industry-Oriented Communication Frameworks. Email and Business Writing Best Practices. Presentation and Interview Skills. Group Discussions and Personal Branding. Corporate Etiquette and Workplace Readiness.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'approaches', 'Multiple Approaches', 'Interactive Simulations & Mock Interviews. Real-time Feedback Loops. Resume Labs and Elevator Pitch Practice. Peer Critique Sessions.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'impact', 'Outcomes and Impact', '85% of students reported increased clarity and confidence in job interviews. Campus recruiters highlighted better articulation and professionalism in placement rounds. MBA & MCA placement coordinators reported smoother pre-placement processes.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'strategic_alignment', 'Strategic Alignment with Acharya''s Vision', 'This initiative aligned seamlessly with Acharya Institute''s goals of: Enhancing Industry Readiness Among Graduates. Elevating Communication as a Core Career Skill. Enabling Seamless Transition from Classroom to Corporate. Strengthening Placement Outcomes through Holistic Training.'),
((SELECT id FROM programs WHERE slug = 'acharya'), 'conclusion', 'Crafting Communicators, Not Just Candidates', 'At Acharya Institute, Rareminds went beyond basic communication training. We helped students shape their voice, articulate their value, and enter the professional world with poise and purpose. The impact was clear: sharper skills, stronger confidence, and a generation ready to make their mark.');
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'pes'), 'introduction', 'Introduction', 'The Rareminds Bootcamp at PES Engineering College, Mandya, contributed to transform aspiring engineers into confident, industry-ready developers. Through an intensive, 45-hour Web Development Bootcamp, we bridged the classroom-to-career gap with a hands-on, real-world coding experience that left students skilled, motivated, and ready for the digital future.'),
((SELECT id FROM programs WHERE slug = 'pes'), 'about', 'About the Program', 'Web Development Bootcamp: From July 24th to 29th, 2023, Rareminds delivered a comprehensive Web Development Bootcamp focused on Full Stack skills. The program immersed students in practical learning, from HTML, CSS, and JavaScript to React, backend integration, APIs, and deployment techniques.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'vels'), 'introduction', 'Introduction', 'Rareminds training programs at VELS University to reshape technical education for first-year students, delivering high-impact, project-based training in emerging technologies. The initiative successfully bridged classroom learning with real-world application, equipping students with future-ready skills and confidence for the evolving digital workplace.'),
((SELECT id FROM programs WHERE slug = 'vels'), 'about', 'About the Program', 'Industrial Metaverse: Two 45-hour experiential training programs were delivered to undergraduate students as part of this collaboration. This program combined cutting-edge tools like VR and AI with hands-on projects, enabling students to simulate real-world environments from day one.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'dsatm'), 'introduction', 'The Real-World Leap: How DSATM Students Gained a Competitive Edge', 'Rareminds has been a long-standing training partner for DSATM, driving student employability through curated, career-oriented workshops. By integrating both technical and soft skill components, these programs empowered engineering and management students with practical tools to thrive in professional settings.'),
((SELECT id FROM programs WHERE slug = 'dsatm'), 'about', 'About the Program', 'MBA Students: 5-Day Advanced Excel Workshop (Sept–Oct 2019). Focused on business analytics and reporting through practical spreadsheet applications.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologies—bridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'about', 'About the Program', 'Through this collaboration, Rareminds delivered four specialized 45-hour experiential training programs to undergraduate students during the Even Semesters of the 2024–2025 academic year. These mandatory programs provided immersive, hands-on learning experiences in the following sectors: Chemical Safety in Battery Management, EV Battery Management Systems, Food Analysis Processing and Preservation, Organic Food Production. Each course blended in-person instruction with LMS-based support, enabling students to work on real-time simulations, hands-on projects, and practical applications from day one. The programs were designed to enhance both technical competencies and employability skills in alignment with industry expectations.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'course_enrollment', 'Course Enrollment by University', 'Organic Food Practices - Total: 2,312 students across Bharathidasan University (1,056), Manonmaniam Sundranar University (569), Alagappa University (294), Madurai Kamaraj University (276), Mother Teresa University (117). Food Analysis Processing and Preservation - Total: 2,230 students across Periyar University (1,419), Annamalai University (589), Bharathiar University (222). Medical Coding - Total: 3,807 students across Thiruvalluvar University (1,532), Annamalai University (1,416), Madurai Kamaraj University (643), Mother Teresa University (216). Agri Business Management - Total: 2,449 students across Thiruvalluvar University (1,237), University of Madras (1,212).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'impact', 'Key Outcomes & Impact', '10,798 students were trained through structured, mentor-led sessions across partner universities in Tamil Nadu. All participants successfully completed comprehensive final projects, showcasing the practical application of their learning. Evaluations were jointly conducted by college faculty and Rareminds'' industry experts. Where applicable, students actively participated in mandatory hackathons—fostering innovation, critical thinking, and collaborative problem-solving. Employability outcomes were strengthened through integrated support for placements, internships, and real-time project experiences. Institutional feedback from TNSDC and participating universities was overwhelmingly positive, noting higher student engagement, curiosity, and application-based learning.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2024'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Delivery of industry-aligned content enhanced the job readiness of Arts and Science graduates.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the Naan Mudhalvan flagship program to significantly enhance the technical education landscape for Arts and Science students across Tamil Nadu. This initiative focused on delivering high-impact, project-based training in critical emerging technologies, effectively bridging traditional classroom learning with practical, real-world applications. The collaboration equipped students with future-ready skills and the confidence essential for success in the evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'about', 'About the Program', 'As part of this strategic collaboration, Rareminds delivered four specialized 45-hour experiential training programs to undergraduate students during the Even Semester of the 2023–2024 academic year. These mandatory courses were designed to provide hands-on experience and practical understanding in key sectors: Agribusiness Management, EV Battery Management, Food Analysis, Organic Food Production Techniques. Each program combined theoretical knowledge with practical application, enabling students to engage in comprehensive projects, simulations, and real-world problem-solving from day one. The curriculum included physical classroom interventions and supplementary LMS-based content, ensuring a dynamic and blended learning experience.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'course_enrollment', 'Detailed Course Enrollment by University', 'Agribusiness Management - Total: 2,072 students across Alagappa University (296), Bharathidasan University (963), Madurai Kamaraj University (223), Mother Teresa University (93), Manonmaniam Sundaranar University (497).EV Battery Management - Total: 14,564 students across multiple universities including Periyar University (3,653), Thiruvalluvar University (2,541), Bharathidasan University (1,749), Annamalai University (1,651), University of Madras (1,472), Manonmaniam Sundaranar University (953), Bharathiar University (879), Madurai Kamaraj University (789), Alagappa University (632), Mother Teresa University (245). Food Analysis - Total: 1,637 students across Thiruvalluvar University (813), University of Madras (824).Organic Food Production Techniques - Total: 2,044 students across Periyar University (1,282), Annamalai University (541), Bharathiar University (221).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'impact', 'Key Outcomes & Impact', '20,317 students trained through structured, mentor-led sessions across various universities in Tamil Nadu. 100% of participants completed comprehensive final projects, demonstrating practical application of their learning. Evaluations were conducted jointly by college faculty and Rareminds'' industry experts. High engagement in mandatory hackathons, wherever applicable, fostering innovation, critical thinking, and collaborative problem-solving. Strengthened employability outcomes, with integrated placement, internship, and hackathon support initiatives. Positive institutional feedback from TNSDC and partner universities, highlighting increased student engagement, curiosity, and application-based learning.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2023'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Delivery of industry-aligned content boosted the job-readiness of Arts and Science graduates.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the "Naan Mudhalvan" flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologies—bridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'about', 'About the Program', 'Through this collaboration, Rareminds delivered specialized 45-hour experiential training programs to undergraduate students during the 4th Semester of the 2024–2025 academic year. These mandatory programs provided immersive, hands-on learning experiences in the following sectors: Food Analysis, Processing and Preservation Techniques, Organic Food Production Techniques, Sustainability & Green Chemistry in EV Sector. The courses blended in-person classes with LMS-based support, enabling students to work on real-time simulations, projects, and practical applications from day one.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'course_enrollment', 'Detailed Course Enrollment by University', '1. Food Analysis, Processing and Preservation Techniques (4th Semester) - Total: 5,219 students across Periyar University (1,351), University of Madras (850), Thiruvalluvar University (929), Annamalai University (565), Manonmaniam Sundaranar University (555), Bharathiar University (323), Alagappa University (301), Madurai Kamaraj University (224), Mother Teresa University (121). 2. Organic Food Production Techniques (4th Semester) - Total: 991 students at Bharathidasan University. 3. Sustainability & Green Chemistry in EV Sector (4th Semester) - Total: 7,483 students across Bharathidasan University (1,693), Annamalai University (1,648), Thiruvalluvar University (1,550), Madurai Kamaraj University (878), Manonmaniam Sundaranar University (968), Alagappa University (516), Mother Teresa University (230).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'impact', 'Key Outcomes & Impact', '21,646 students trained through hands-on, mentor-led sessions across major Tamil Nadu universities. 100% project completion across all enrolled students, evaluated jointly by Master Assessor Faculty and Rareminds'' industry experts. 70%+ student participation in mandatory hackathons promotes innovation, collaboration, and problem-solving. Enhanced employability through post-training support, including placement drives and internship opportunities, targeting at least 25% placement conversion. Positive feedback from TNSDC and universities citing better engagement, curiosity, and practical understanding among students.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-4th-sem-2025'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Provided students with industry-relevant, practical skills.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-6th-sem-2025'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the "Naan Mudhalvan" flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologies—bridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-6th-sem-2025'), 'about', 'About the Program', 'Through this collaboration, Rareminds delivered specialized 45-hour experiential training programs to undergraduate students during the 6th Semester of the 2024–2025 academic year. These mandatory programs provided immersive, hands-on learning experiences in the following sectors: Chemical Safety in Battery Management, EV Battery Management System. The courses blended in-person classes with LMS-based support, enabling students to work on real-time simulations, projects, and practical applications from day one.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-6th-sem-2025'), 'course_enrollment', 'Detailed Course Enrollment by University', '1. Chemical Safety in Battery Management (6th Semester) - Total: 2,755 students across Manonmaniam Sundaranar University (1,044), Madurai Kamaraj University (893), Alagappa University (572), Mother Teresa University (246). 2. EV Battery Management System (6th Semester) - Total: 5,198 students across Annamalai University (1,811), Thiruvalluvar University (1,740), Bharathidasan University (1,647).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-6th-sem-2025'), 'impact', 'Key Outcomes & Impact', '21,646 students trained through hands-on, mentor-led sessions across major Tamil Nadu universities. 100% project completion across all enrolled students, evaluated jointly by Master Assessor Faculty and Rareminds'' industry experts. 70%+ student participation in mandatory hackathons promotes innovation, collaboration, and problem-solving. Enhanced employability through post-training support, including placement drives and internship opportunities, targeting at least 25% placement conversion. Positive feedback from TNSDC and universities citing better engagement, curiosity, and practical understanding among students.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-6th-sem-2025'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Innovation & Learning Approach: By integrating innovation, hands-on learning, and outcome-driven models, Rareminds enhanced the overall learning experience.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'introduction', 'Introduction', 'Rareminds proudly partnered with the Tamil Nadu Skill Development Corporation (TNSDC) under the "Naan Mudhalvan" flagship initiative to transform technical education for Arts and Science students across Tamil Nadu. This program focused on delivering high-impact, project-based training in critical emerging technologies—bridging classroom theory with real-world practice. The partnership empowered students with future-ready skills, practical exposure, and the confidence to meet the demands of an evolving digital and industrial workforce.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'about', 'About the Program', 'Through this collaboration, Rareminds delivered five specialized 45-hour experiential training programs to undergraduate students during the Odd Semester (5th) of the 2025–2026 academic year. These mandatory programs provided immersive, hands-on learning experiences in the following sectors: Good Manufacturing Practices, Medical Coding, Food Safety and Quality Management. The courses blended in-person classes with LMS-based support, enabling students to work on real-time simulations, projects, and practical applications from day one.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'course_enrollment', 'Detailed Course Enrollment by University', '1. Medical Coding (5th Semester) - Total: 3,886 students across Periyar University (2,987), Bharathiar University (899). 2. GMP (5th Semester) - Total: 5,049 students across Periyar University (2,148), Manonmaniam Sundaranar University (949), Madurai Kamaraj University (797), Alagappa University (508), Bharathiar University (420), Mother Teresa University (227). 3. Food Safety and Quality Management (5th Semester) - Total: 5,560 students across Periyar University (1,283), Thiruvalluvar University (888), Bharathidasan University (868), Annamalai University (556), University of Madras (557), Manonmaniam Sundaranar University (540), Bharathiar University (301), Alagappa University (292), Madurai Kamaraj University (157), Mother Teresa University (118).'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'impact', 'Objectives', '14,495 students to be trained through hands-on, mentor-led sessions across major Tamil Nadu universities. 100% project completion across all enrolled students, evaluated jointly by Master Assessor Faculty and Rareminds'' industry experts. 70%+ student participation in mandatory hackathons promotes innovation, collaboration, and problem-solving. Enhanced employability through post-training support, including placement drives and internship opportunities, targeting at least 25% placement conversion. Positive feedback from TNSDC and universities citing better engagement, curiosity, and practical understanding among students.'),
((SELECT id FROM programs WHERE slug = 'naan-mudhalvan-2025'), 'strategic_alignment', 'Strategic Alignment with TNSDC Goals', 'Skill Development & Employability: Provide students with industry-relevant, practical skills.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'tripura'), 'introduction', 'Equipping Candidates for Global Careers with Confidence & Clarity', 'Overseas job interviews demand more than just qualifications — they require candidates to present themselves with poise, adapt to cross-cultural environments, and navigate high-stakes conversations effectively. Tripura Skill Development Corporation (TSDC) identified the need to prepare aspiring overseas placement candidates with focused, practical training that would address both interview performance and communication competency. A targeted approach was implemented to ensure that participants — ranging from ITI graduates to young professionals — received actionable strategies, hands-on practice, and cross-cultural readiness for international job markets. Rareminds, under the leadership of CEO Dr. Subhashini, delivered a structured 10-hour training program designed to build both competence and confidence. Dr. Subhashini personally conducted the sessions, bringing strategic insights and real-world experience directly to participants.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'programs', 'Program Delivery', 'Total Training Hours: 10 hours. Schedule: 2 hours/day across 5 days. Participants Trained: 200 candidates (Two batches of 100 each). Participant Profile: ITI, Diploma, Graduates, Postgraduates, Young Professionals. Trainer: Dr. Subhashini, CEO, Rareminds.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'modules', 'Modules Covered', 'Interview Skills: Effective Resume and Cover Letter Writing, Common Interview Questions & Best Practices, Non-verbal Communication & Body Language, Handling Difficult Questions & Stress Management, Mock Interviews with Personalized Feedback. Cross-cultural Communication: Understanding Cultural Differences and Sensitivities, Communication Strategies for Diverse Audiences, Global Business Etiquette, Intercultural Conflict Resolution & Negotiation.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'approaches', 'Multiple Approaches', 'Interactive Presentations & Case Studies. Group Discussions & Peer Activities. Roleplays & Interview Simulations. Individualized Coaching & Feedback.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'impact', 'Outcomes and Impact', '95% participants reported improved confidence in handling interviews. 92% demonstrated better articulation in mock interview evaluations. 87% showed improvement in cross-cultural awareness and etiquette. 100% of participants completed mock interviews with personalized feedback. Post-training self-assessment scores improved by an average of 40% across key skill areas. Participant feedback emphasized high satisfaction with the hands-on approach, real-world relevance, and the opportunity to practice in simulated interview environments.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'strategic_alignment', 'Strategic Alignment with TSDC Goals', 'This initiative directly supported TSDC''s mission to strengthen global employability for regional youth, bridge skill gaps through targeted communication and interview training, prepare candidates for diverse cultural and professional environments, and enhance placement success rates through practical readiness.'),
((SELECT id FROM programs WHERE slug = 'tripura'), 'conclusion', 'Turning Aspirants into Global Professionals', 'Through this focused intervention, Rareminds — under the direct leadership and facilitation of CEO Dr. Subhashini — empowered Tripura''s overseas placement aspirants with the tools, confidence, and global readiness essential for success. The program served not only as a skill-building platform but also as a mindset transformation, directly contributing to TSDC''s vision of creating globally competitive talent.');
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'introduction', 'Introduction', 'Rareminds partnered with Tamil Nadu Skill Development Corporation (TNSDC) to improve English and personality development among students in government welfare hostels. This was hands-on training that equipped students with critical communication skills and confidence for their future academic and professional life.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-iti-spoken-english'), 'about', 'About the Program', 'English & Personality Development: A full English and Personality Development program was offered to 2nd and 3rd year students in Tribal, ADW, BC, MBC, DNC, and Minorities Welfare Department Hostels.
INSERT INTO program_sections (program_id, section_key, title, content) VALUES
((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 'introduction', 'Implement Proven Vocational Programs for Your GHSS Students', 'Rareminds, in a significant partnership with the Tamil Nadu Skill Development Corporation, recently concluded a transformative 7-day (45-hour) vocational training program across 121 Government Higher Secondary Schools (GHSS). This initiative was designed to empower 12th-grade (2nd PUC) students with tangible, in-demand skills, paving the way for entrepreneurship and enhancing employability in key growth sectors. The program successfully reached 1,974 students out of 3,065 students allocated by the Tamil Nadu Skill Development Corporation, demonstrating Rareminds'' expertise in large-scale, impactful educational delivery.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 'about', 'Why Partner with Rareminds?', 'Choosing Rareminds means choosing a partner dedicated to your school''s success and your students'' futures. Here''s what you gain: Effortless NEP 2020 Alignment: Seamlessly integrate the mandated skill-based, experiential learning into your curriculum with our ready-to-deploy, NEP-aligned programs. Enhanced Student Employability: Give your students a competitive edge with practical, in-demand skills and entrepreneurship training that prepares them for immediate career opportunities. Future-Proof Curriculum: Offer exciting, modern vocational training in high-growth sectors like food technology and entrepreneurship, meeting parent expectations and student interests. Proven Government Partnership: We have a successful track record of executing large-scale, complex projects with government bodies, ensuring reliable implementation. Fully Integrated Program Delivery: Reduce your administrative burden. We handle everything from needs assessment and customization to expert delivery and detailed reporting. Measurable Impact: Showcase your school''s success with structured reporting and feedback, demonstrating tangible improvements in student skills and confidence within a single term.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 'impact', 'Cloud Kitchen Operations', 'This stream was designed to give students a comprehensive understanding of the burgeoning cloud kitchen industry, equipping them with the knowledge to launch and manage their food ventures. Key learning areas included: Strategic Setup: Understanding the criticality of location selection (considering proximity, utilities, zoning laws, and cost) and designing an optimal kitchen layout for efficient workflow, storage, and health compliance. Operational Excellence: Identifying essential cooking equipment, refrigeration, prep tools, and packaging supplies, and integrating crucial technology like POS systems and online ordering platforms. Business Fundamentals: Developing skills in initial setup budgeting (covering rent, utilities, equipment, and inventory), menu design (balancing variety and efficiency), and effective pricing strategies (cost-based, market-based, and value-based). Supply Chain & Safety: Mastering food sourcing, supplier evaluation, inventory management (including Just-In-Time systems), and adhering to comprehensive food safety protocols and regulatory compliance standards.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 'strategic_alignment', 'Agri-Food Processing & Preservation', 'This comprehensive 40-hour curriculum equips students with vital knowledge of the agri-food industry. It focuses on practical ways to enhance food value, improve safety standards, and extend shelf life. A key objective is to prepare students for diverse career opportunities within this crucial sector. Understanding the Fundamentals: Students receive a clear overview of food processing and preservation, covering its definition, importance, and various types. Mastering Preservation Methods: The course focused on a wide array of preservation techniques. These include Thermal Processing (like pasteurization and canning), Cold Preservation (by refrigeration and freezing), Dehydration (such as sun drying and hot air drying), Chemical Preservation (using preservatives and fermentation), and innovative Novel Techniques like vacuum packaging. Gaining Hands-On Experience: Ten hours of practical sessions allow students to apply their learning directly through activities such as canning, bottling, pickling, fermentation, drying fruits and vegetables, and proper freezing techniques. Ensuring Food Safety and Quality: This module emphasizes the critical aspects of food safety principles and hygiene practices. Students are introduced to the basics of HACCP (Hazard Analysis and Critical Control Points), along with methods for quality control in food processing and understanding packaging and labeling requirements. Exploring Career Pathways: The course guides students in exploring opportunities for small business startups in the food sector and understanding the variety of job roles available within the broader food processing industry. This widely adopted vocational program was implemented in 116 schools, where 1,570 students gained invaluable practical skills and knowledge.'),
((SELECT id FROM programs WHERE slug = 'tnsdc-schools'), 'conclusion', 'A Commitment to Skilling Tamil Nadu', 'This successful GHSS project underscores Rareminds'' dedication to delivering high-quality, large-scale vocational training in collaboration with government bodies. By empowering nearly 2,000 students with practical knowledge and entrepreneurial insights, we are actively shaping a more skilled, confident, and future-ready generation for your School.');
